<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Conway's Game of Life</title>
    <style>
        body {
            background-color: #121212;
            color: #e0e0e0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            margin: 0;
            overflow: hidden;
        }

        .controls {
            margin-bottom: 20px;
            display: flex;
            gap: 10px;
            z-index: 10;
        }

        button {
            background: #2a2a2a;
            color: #00ff88;
            border: 2px solid #00ff88;
            padding: 8px 16px;
            cursor: pointer;
            font-weight: bold;
            text-transform: uppercase;
            transition: all 0.2s ease;
            border-radius: 4px;
            outline: none;
        }

        button:hover {
            background: #00ff88;
            color: #121212;
            box-shadow: 0 0 15px rgba(0, 255, 136, 0.4);
        }

        button:active {
            transform: scale(0.95);
        }

        #life {
            background-color: #000;
            border: 4px solid #333;
            box-shadow: 0 0 30px rgba(0,0,0,0.5);
            cursor: crosshair;
            image-rendering: pixelated;
        }

        .title {
            margin-bottom: 10px;
            font-size: 24px;
            letter-spacing: 2px;
            color: #00ff88;
            text-shadow: 0 0 10px rgba(0, 255, 136, 0.3);
        }
    </style>
</head>
<body>

    <div class="title">GAME OF LIFE</div>
    <div class="controls">
        <button id="step">Step</button>
        <button id="play">Play</button>
        <button id="random">Random</button>
        <button id="clear">Clear</button>
    </div>
    <canvas id="life"></canvas>

    <script>
        (function() {
            const COLS = 60;
            const ROWS = 60;
            const CELL_SIZE = 10; // Total canvas size: 600x600

            const canvas = document.getElementById('life');
            const ctx = canvas.getContext('2d');
            canvas.width = COLS * CELL_SIZE;
            canvas.height = ROWS * CELL_SIZE;

            // State: 2D array [row][col]
            let grid = Array.from({ length: ROWS }, () => new Array(COLS).fill(0));
            let isPlaying = false;
            let playInterval = null;
            let isPainting = false;
            let paintValue = 1;

            function draw() {
                ctx.fillStyle = '#000';
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                ctx.fillStyle = '#00ff88';
                for (let y = 0; y < ROWS; y++) {
                    for (let x = 0; x < COLS; x++) {
                        if (grid[y][x] === 1) {
                            ctx.fillRect(x * CELL_SIZE + 1, y * CELL_SIZE + 1, CELL_SIZE - 2, CELL_SIZE - 2);
                        }
                    }
                }
            }

            const lifeAPI = {
                w: COLS,
                h: ROWS,
                get: function(x, y) {
                    if (x < 0 || x >= COLS || y < 0 || y >= ROWS) return 0;
                    return grid[y][x];
                },
                set: function(x, y, v) {
                    if (x >= 0 && x < COLS && y >= 0 && y < ROWS) {
                        grid[y][x] = v ? 1 : 0;
                        draw();
                    }
                },
                step: function() {
                    const nextGrid = Array.from({ length: ROWS }, () => new Array(COLS).fill(0));

                    for (let y = 0; y < ROWS; y++) {
                        for (let x = 0; x < COLS; x++) {
                            let neighbors = 0;
                            // Check 8 surrounding cells
                            for (let dy = -1; dy <= 1; dy++) {
                                for (let dx = -1; dx <= 1; dx++) {
                                    if (dx === 0 && dy === 0) continue;
                                    neighbors += lifeAPI.get(x + dx, y + dy);
                                }
                            }

                            const current = grid[y][x];
                            // B3/S23 Rules
                            if (current === 1 && (neighbors === 2 || neighbors === 3)) {
                                nextGrid[y][x] = 1;
                            } else if (current === 0 && neighbors === 3) {
                                nextGrid[y][x] = 1;
                            } else {
                                nextGrid[y][x] = 0;
                            }
                        }
                    }
                    grid = nextGrid;
                    draw();
                },
                clear: function() {
                    grid = Array.from({ length: ROWS }, () => new Array(COLS).fill(0));
                    draw();
                }
            };

            // Expose API to window for grading
            window.life = lifeAPI;

            // UI Logic
            document.getElementById('step').onclick = () => lifeAPI.step();
            document.getElementById('clear').onclick = () => lifeAPI.clear();
            document.getElementById('random').onclick = () => {
                for (let y = 0; y < ROWS; y++) {
                    for (let x = 0; x < COLS; x++) {
                        grid[y][x] = Math.random() > 0.8 ? 1 : 0;
                    }
                }
                draw();
            };

            document.getElementById('play').onclick = function() {
                isPlaying = !isPlaying;
                this.textContent = isPlaying ? 'Pause' : 'Play';
                if (isPlaying) {
                    playInterval = setInterval(() => lifeAPI.step(), 100);
                } else {
                    clearInterval(playInterval);
                }
            };

            // Interaction Logic
            function handleInput(e) {
                const rect = canvas.getBoundingClientRect();
                const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
                const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);

                if (x >= 0 && x < COLS && y >= 0 && y < ROWS) {
                    lifeAPI.set(x, y, paintValue);
                }
            }

            canvas.onmousedown = (e) => {
                isPainting = true;
                const rect = canvas.getBoundingClientRect();
                const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
                const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
                // Set paint mode based on the cell we clicked first
                paintValue = lifeAPI.get(x, y) === 1 ? 0 : 1;
                handleInput(e);
            };

            window.onmousemove = (e) => {
                if (isPainting) handleInput(e);
            };

            window.onmouseup = () => {
                isPainting = false;
            };

            // Initial draw
            draw();
        })();
    </script>
</body>
</html>
